<span class="line"><span style="color:#795E26;">git</span><span style="color:#000000;"> </span><span style="color:#A31515;">rev-parse</span><span style="color:#000000;"> </span><span style="color:#0000FF;">---short</span><span style="color:#000000;"> </span><span style="color:#A31515;">HEAD</span><span style="color:#000000;"> </span><span style="color:#A31515;">//显示HEAD提交的简短SHA1值</span></span>
